  switch (input.role) {
    case "story_implementor":
      return "ImplementorResult";
    case "story_verifier":
      return "StoryVerifierResult";
    case "quick_fixer":
      return "QuickFixResult";
    case "epic_verifier":
      return "EpicVerifierResult";
    case "epic_synthesizer":
      return "EpicSynthesisResult";
  }
}

