import { execFile } from "node:child_process";
import { promisify } from "node:util";

import { z } from "zod";

const execFileAsync = promisify(execFile);

export type ProviderName = "claude-code" | "codex" | "copilot";

export interface ProviderExecutionRequest<TResult> {
  prompt: string;
  cwd: string;
  model: string;
  reasoningEffort: string;
  resumeSessionId?: string;
  timeoutMs: number;
  resultSchema?: z.ZodType<TResult>;
}

export interface ProviderExecutionResult<TResult> {
  provider: ProviderName;
  sessionId?: string;
  stdout: string;
  stderr: string;
  exitCode: number;
  parsedResult?: TResult;
  parseError?: string;
  errorCode?: string;
}

export interface ProviderAdapter {
  provider: ProviderName;
  execute<TResult>(
    request: ProviderExecutionRequest<TResult>
  ): Promise<ProviderExecutionResult<TResult>>;
}

function redactSensitiveText(text: string): string {
  return text
    .replace(/\bBearer\s+[A-Za-z0-9._-]+\b/gi, "Bearer [REDACTED]")
    .replace(/\b(token|auth|authorization|api[_-]?key)\s*[:=]\s*\S+/gi, "$1=[REDACTED]");
}

function extractSessionId(value: Record<string, unknown>): string | undefined {
  for (const key of ["sessionId", "session_id"]) {
    const candidate = value[key];
    if (typeof candidate === "string" && candidate.trim().length > 0) {
      return candidate.trim();
    }
  }

  return undefined;
}

function parseNestedJson(value: unknown): unknown {
  if (typeof value !== "string") {
    return value;
  }

  try {
    return JSON.parse(value);
  } catch {
    return undefined;
  }
}

export function parseProviderPayload<TResult>(input: {
  stdout: string;
  resultSchema?: z.ZodType<TResult>;
}): {
  parsedResult?: TResult;
  sessionId?: string;
  parseError?: string;
} {
  const trimmed = input.stdout.trim();
  if (trimmed.length === 0) {
    return {
      parseError: "Provider stdout was empty.",
    };
  }

  let root: unknown;
  try {
    root = JSON.parse(trimmed);
  } catch {
    return {
      parseError: "Provider stdout was not exact JSON.",
    };
  }

  if (!root || typeof root !== "object" || Array.isArray(root)) {
    return {
      parseError: "Provider stdout was not a JSON object.",
    };
  }

  const rootRecord = root as Record<string, unknown>;
  const resultSchema = input.resultSchema ?? z.unknown();
  const direct = resultSchema.safeParse(rootRecord);
  if (direct.success) {
    return {
      parsedResult: direct.data as TResult,
      sessionId: extractSessionId(rootRecord),
    };
  }

  for (const field of ["result", "text"]) {
    const nested = parseNestedJson(rootRecord[field]);
    const parsed = resultSchema.safeParse(nested);
    if (parsed.success) {
      return {
        parsedResult: parsed.data as TResult,
        sessionId: extractSessionId(rootRecord),
      };
    }
  }

  return {
    parseError: "Provider output did not match the expected JSON payload.",
  };
}

export async function runProviderCommand(params: {
  provider: ProviderName;
  executable: string;
  args: string[];
  cwd: string;
  env?: Record<string, string | undefined>;
  timeoutMs: number;
}): Promise<{
  provider: ProviderName;
  stdout: string;
  stderr: string;
  exitCode: number;
  errorCode?: string;
}> {
  try {
    const result = await execFileAsync(params.executable, params.args, {
      cwd: params.cwd,
      env: {
        ...process.env,
        ...params.env,
      },
      timeout: params.timeoutMs,
    });

    return {
      provider: params.provider,
      stdout: redactSensitiveText(result.stdout.trim()),
      stderr: redactSensitiveText(result.stderr.trim()),
      exitCode: 0,
    };
  } catch (error) {
    const failed = error as {
      code?: string | number;
      stdout?: string;
      stderr?: string;
      message?: string;
    };

    return {
      provider: params.provider,
      stdout: redactSensitiveText(failed.stdout?.trim() ?? ""),
      stderr: redactSensitiveText(
        failed.stderr?.trim() ?? failed.message ?? String(error)
      ),
      exitCode:
        typeof failed.code === "number" ? failed.code : 1,
      errorCode:
        typeof failed.code === "string" ? failed.code : undefined,
    };
  }
}

import { relative, resolve } from "node:path";

import { loadConfig } from "c12";
import { z } from "zod";

export const RUN_CONFIG_FILE_NAME = "impl-run.config.json";

export const reasoningEffortSchema = z.enum(["low", "medium", "high", "xhigh"]);
export const primaryHarnessSchema = z.literal("claude-code");
export const secondaryHarnessSchema = z.enum(["codex", "copilot", "none"]);

export const roleAssignmentSchema = z.object({
  secondary_harness: secondaryHarnessSchema,
  model: z.string().min(1),
  reasoning_effort: reasoningEffortSchema,
});

export const epicVerifierAssignmentSchema = roleAssignmentSchema.extend({
  label: z.string().min(1),
});

export const implRunConfigSchema = z
  .object({
    version: z.literal(1),
    primary_harness: primaryHarnessSchema,
    story_implementor: roleAssignmentSchema,
    quick_fixer: roleAssignmentSchema,
    story_verifier_1: roleAssignmentSchema,
    story_verifier_2: roleAssignmentSchema,
    self_review: z.object({
      passes: z.number().int().min(1).max(5),
    }),
    epic_verifiers: z.array(epicVerifierAssignmentSchema).min(1),
    epic_synthesizer: roleAssignmentSchema,
  })
  .superRefine((value, ctx) => {
    if (value.story_implementor.secondary_harness === "copilot") {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message:
          "story_implementor.secondary_harness cannot be copilot in v1",
        path: ["story_implementor", "secondary_harness"],
      });
    }

    const seenLabels = new Set<string>();
    for (const [index, verifier] of value.epic_verifiers.entries()) {
      if (seenLabels.has(verifier.label)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: "Duplicate epic verifier label",
          path: ["epic_verifiers", index, "label"],
        });
      }
      seenLabels.add(verifier.label);
    }
  });

export type ReasoningEffort = z.infer<typeof reasoningEffortSchema>;
export type PrimaryHarness = z.infer<typeof primaryHarnessSchema>;
export type SecondaryHarness = z.infer<typeof secondaryHarnessSchema>;
export type RoleAssignment = z.infer<typeof roleAssignmentSchema>;
export type EpicVerifierAssignment = z.infer<typeof epicVerifierAssignmentSchema>;
export type ImplRunConfig = z.infer<typeof implRunConfigSchema>;

export function resolveRunConfigPath(
  specPackRoot: string,
  configPath?: string
): string {
  if (!configPath) {
    return resolve(specPackRoot, RUN_CONFIG_FILE_NAME);
  }

  return resolve(specPackRoot, configPath);
}

export async function loadRunConfig(input: {
  specPackRoot: string;
  configPath?: string;
}): Promise<ImplRunConfig> {
  const resolvedPath = resolveRunConfigPath(input.specPackRoot, input.configPath);
  const { config } = await loadConfig({
    cwd: resolve(input.specPackRoot),
    configFile: relative(resolve(input.specPackRoot), resolvedPath),
    configFileRequired: true,
    rcFile: false,
    globalRc: false,
    packageJson: false,
    dotenv: false,
    extend: false,
  });

  return implRunConfigSchema.parse(config);
}

