const ALLOWED_TECH_DESIGN_COMPANIONS = [
  "tech-design-cli-runtime.md",
  "tech-design-skill-process.md",
] as const;

async function pathIsDirectory(path: string): Promise<boolean> {
  try {
    return (await stat(path)).isDirectory();
  } catch {
    return false;
  }
}

function resolveTechDesignArtifacts(entries: string[]): {
  techDesignShape: "two-file" | "four-file";
  companionPaths: string[];
  blockers: string[];
} {
  const companionFiles = entries
    .filter(
      (entry) =>
        entry.startsWith("tech-design-") &&
        entry.endsWith(".md") &&
        entry !== "tech-design.md"
    )
    .sort((left, right) => left.localeCompare(right));

  if (companionFiles.length === 0) {
    return {
      techDesignShape: "two-file",
      companionPaths: [],
      blockers: [],
    };
  }

  const allowed = [...ALLOWED_TECH_DESIGN_COMPANIONS].sort((left, right) =>
    left.localeCompare(right)
  );

  if (JSON.stringify(companionFiles) === JSON.stringify(allowed)) {
    return {
      techDesignShape: "four-file",
      companionPaths: companionFiles,
      blockers: [],
    };
  }

  return {
    techDesignShape: "two-file",
    companionPaths: [],
    blockers: [
      "Invalid tech-design companion layout: expected tech-design-cli-runtime.md and tech-design-skill-process.md for the four-file configuration",
    ],
  };
}

export async function inspectSpecPack(specPackRoot: string): Promise<InspectResult> {
  const resolvedRoot = resolve(specPackRoot);
  const epicPath = join(resolvedRoot, "epic.md");
  const techDesignPath = join(resolvedRoot, "tech-design.md");
  const testPlanPath = join(resolvedRoot, "test-plan.md");
  const storiesDir = join(resolvedRoot, "stories");
  const storiesFile = join(resolvedRoot, "stories.md");
  const blockers: string[] = [];
  const notes: string[] = [];

  const repoRoot = await resolveGitRepoRoot(resolvedRoot);
  if (!repoRoot) {
    blockers.push(`Spec-pack root is not inside a git repo: ${resolvedRoot}`);
  }

  if (!(await pathExists(epicPath))) {
    blockers.push("Missing required artifact: epic.md");
  }

  if (!(await pathExists(techDesignPath))) {
    blockers.push("Missing required artifact: tech-design.md");
  }

  if (!(await pathExists(testPlanPath))) {
    blockers.push("Missing required artifact: test-plan.md");
  }

  const storiesDirExists = await pathIsDirectory(storiesDir);
  if (!storiesDirExists && (await pathExists(storiesFile))) {
    blockers.push("Expected stories/ directory but found stories.md");
  } else if (!storiesDirExists) {
    blockers.push("Missing required artifact: stories/");
  }

  const rootEntries = await readdir(resolvedRoot);
  const techDesignArtifacts = resolveTechDesignArtifacts(rootEntries);
  blockers.push(...techDesignArtifacts.blockers);

  const storyOrder = storiesDirExists
    ? await resolveStoryOrder(storiesDir)
    : { status: "ready" as const, stories: [], notes: [] };
  notes.push(...storyOrder.notes);
  const implInsertPath = join(
    resolvedRoot,
    "custom-story-impl-prompt-insert.md"
  );
  const verifierInsertPath = join(
    resolvedRoot,
    "custom-story-verifier-prompt-insert.md"
  );
  const implInsertExists = await pathExists(implInsertPath);
  const verifierInsertExists = await pathExists(verifierInsertPath);

  if (implInsertExists && !(await pathReadable(implInsertPath))) {
    blockers.push(
      "Unreadable prompt insert: custom-story-impl-prompt-insert.md"
    );
  }

  if (verifierInsertExists && !(await pathReadable(verifierInsertPath))) {
    blockers.push(
      "Unreadable prompt insert: custom-story-verifier-prompt-insert.md"
    );
  }

  const status =
    blockers.length > 0
      ? "blocked"
      : storyOrder.status === "needs-user-decision"
        ? "needs-user-decision"
        : "ready";

  const result: InspectResult = {
    status,
    specPackRoot: resolvedRoot,
    techDesignShape: techDesignArtifacts.techDesignShape,
    artifacts: {
      epicPath,
      techDesignPath,
      techDesignCompanionPaths: techDesignArtifacts.companionPaths.map((file) =>
        join(resolvedRoot, file)
      ),
      testPlanPath,
      storiesDir,
    },
    stories: storyOrder.stories,
    inserts: {
      customStoryImplPromptInsert: implInsertExists ? "present" : "absent",
      customStoryVerifierPromptInsert: verifierInsertExists
        ? "present"
        : "absent",
    },
    blockers,
    notes,
  };

  return inspectResultSchema.parse(result);
}

import { readdir } from "node:fs/promises";
import { join, resolve } from "node:path";

import { pathExists, readTextFile } from "./fs-utils";
import type { CliError } from "./result-contracts";

export interface GateDiscoveryResult {
  status: "ready" | "needs-user-decision";
  verificationGates?: {
    storyGate: string;
    epicGate: string;
    storyGateSource: string;
    epicGateSource: string;
  };
  errors: CliError[];
  notes: string[];
}

interface GateSourceCandidates {
  story: string[];
  epic: string[];
  source: string;
}

function uniqueValues(values: string[]): string[] {
  return [...new Set(values.map((value) => value.trim()).filter(Boolean))];
}

function resolveGateValue(input: {
  explicitValue?: string;
  sourceCandidates: GateSourceCandidates[];
  gate: "story" | "epic";
}): {
  value?: string;
  source?: string;
  ambiguous: boolean;
} {
  if (input.explicitValue) {
    return {
      value: input.explicitValue,
      source: "explicit CLI flag",
      ambiguous: false,
    };
  }

  for (const candidateSet of input.sourceCandidates) {
    const values = uniqueValues(candidateSet[input.gate]);
    if (values.length > 1) {
      return {
        ambiguous: true,
      };
    }

    if (values.length === 1) {
      return {
        value: values[0],
        source: candidateSet.source,
        ambiguous: false,
      };
    }
  }

  return {
    ambiguous: false,
  };
}

async function packageScriptCandidates(
  specPackRoot: string
): Promise<GateSourceCandidates[]> {
  const packageJsonPath = join(specPackRoot, "package.json");
  if (!(await pathExists(packageJsonPath))) {
    return [];
  }

  const packageJson = JSON.parse(await readTextFile(packageJsonPath)) as {
    scripts?: Record<string, string>;
  };
  const scripts = packageJson.scripts ?? {};

  if (!scripts["green-verify"] && !scripts["verify-all"]) {
    return [];
  }

  return [
    {
      story: scripts["green-verify"] ? [scripts["green-verify"]] : [],
      epic: scripts["verify-all"] ? [scripts["verify-all"]] : [],
      source: "package.json scripts",
    },
  ];
}

async function docCandidates(specPackRoot: string): Promise<GateSourceCandidates[]> {
  const candidates: GateSourceCandidates = {
    story: [],
    epic: [],
    source: "project policy docs",
  };

  for (const fileName of ["AGENTS.md", "README.md"]) {
    const filePath = join(specPackRoot, fileName);
    if (!(await pathExists(filePath))) {
      continue;
    }

    const content = await readTextFile(filePath);
    for (const match of content.matchAll(/^Story Gate:\s*(.+)$/gim)) {
      candidates.story.push(match[1]);
    }
    for (const match of content.matchAll(/^Epic Gate:\s*(.+)$/gim)) {
      candidates.epic.push(match[1]);
    }
  }

  if (candidates.story.length === 0 && candidates.epic.length === 0) {
    return [];
  }

  return [candidates];
}

async function ciCandidates(specPackRoot: string): Promise<GateSourceCandidates[]> {
  const workflowsDir = join(specPackRoot, ".github", "workflows");
  if (!(await pathExists(workflowsDir))) {
    return [];
  }

  const entries = await readdir(workflowsDir, { withFileTypes: true });
  const candidates: GateSourceCandidates = {
    story: [],
    epic: [],
    source: "CI configuration",
  };

  for (const entry of entries) {
    if (!entry.isFile() || !entry.name.match(/\.ya?ml$/)) {
      continue;
    }

    const content = await readTextFile(join(workflowsDir, entry.name));
    for (const match of content.matchAll(/run:\s*(.+)$/gim)) {
      const command = match[1].trim();
      if (command.includes("green-verify")) {
        candidates.story.push(command);
      }
      if (command.includes("verify-all")) {
        candidates.epic.push(command);
      }
    }
  }

  if (candidates.story.length === 0 && candidates.epic.length === 0) {
    return [];
  }

  return [candidates];
}

export async function resolveVerificationGates(input: {
  specPackRoot: string;
  explicitStoryGate?: string;
  explicitEpicGate?: string;
}): Promise<GateDiscoveryResult> {
  const specPackRoot = resolve(input.specPackRoot);
  const sourceCandidates = [
    ...(await packageScriptCandidates(specPackRoot)),
    ...(await docCandidates(specPackRoot)),
    ...(await ciCandidates(specPackRoot)),
  ];
  const storyResolution = resolveGateValue({
    explicitValue: input.explicitStoryGate,
    sourceCandidates,
    gate: "story",
  });
  const epicResolution = resolveGateValue({
    explicitValue: input.explicitEpicGate,
    sourceCandidates,
    gate: "epic",
  });

  if (
    storyResolution.ambiguous ||
    epicResolution.ambiguous ||
    !storyResolution.value ||
    !epicResolution.value ||
    !storyResolution.source ||
    !epicResolution.source
  ) {
    return {
      status: "needs-user-decision",
      errors: [
        {
          code: "VERIFICATION_GATE_UNRESOLVED",
          message: "Verification gate policy is ambiguous",
          detail:
            "Provide --story-gate and --epic-gate explicitly or clarify the project policy.",
        },
      ],
      notes: [],
    };
  }

  return {
    status: "ready",
    verificationGates: {
      storyGate: storyResolution.value,
      epicGate: epicResolution.value,
      storyGateSource: storyResolution.source,
      epicGateSource: epicResolution.source,
    },
    errors: [],
    notes: [],
  };
}

